import torch

def bucketize(v, boundaries):
    n = v.shape[0]
    m = boundaries.shape[0]
    out = torch.zeros(n, dtype=torch.int64)
    for k in range(n):
        count = 0
        for t in range(m):
            if boundaries[t] < v[k]:
                count += 1
        out[k] = count
    return out

